"use strict";parserFactory.register("lnmtl.com",()=>new LnmtlParser);class LnmtlParser extends Parser{constructor(){super()}populateUIImpl(){document.getElementById("removeOriginalRow").hidden=!1,document.getElementById("removeTranslatedRow").hidden=!1}getChapterUrls(e){let t=LnmtlParser.findVolumesList(e);if(0!==t.length)return LnmtlParser.fetchChapterLists(t,HttpClient.fetchJson).then(function(e){return LnmtlParser.mergeChapterLists(e)});let r=e.querySelector("#volumes-container table");return Promise.resolve(util.hyperlinksToChapterList(r))}findContent(e){return e.querySelector("div.chapter-body")}findChapterTitle(e){return e.querySelector("h3.dashhead-title")}customRawDomToContentStep(e,t){for(let e of t.querySelectorAll("sentence"))if(this.userPreferences.removeOriginal.value&&"original"===e.className)e.remove();else if(this.userPreferences.removeTranslated.value&&"translated"===e.className)e.remove();else{let t=e.ownerDocument.createElement("p");t.innerText=e.innerText,e.replaceWith(t)}}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.jumbotron.novel")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.description")]}static findVolumesList(e){let t="lnmtl.volumes = ",r=util.getElement(e,"script",e=>0<=e.textContent.indexOf(t));return null!==r?util.locateAndExtractJson(r.textContent,t):[]}static fetchChapterLists(e,t){return Promise.all(e.map(e=>LnmtlParser.fetchChapterListsForVolume(e,t)))}static fetchChapterListsForVolume(e,t){let r=LnmtlParser.makeChapterListUrl(e.id,1);return t(r).then(function(r){let l=r.json,n=[Promise.resolve(r)];for(let r=2;r<=l.last_page;++r){let l=LnmtlParser.makeChapterListUrl(e.id,r);n.push(t(l))}return Promise.all(n)})}static makeChapterListUrl(e,t){return`http://lnmtl.com/chapter?page=${t}&volumeId=${e}`}static mergeChapterLists(e){let t=[];for(let r of e)for(let e of r)for(let r of e.json.data)t.push({sourceUrl:r.site_url,title:"#"+r.number+": "+r.title,newArc:null});return t}}